      "code": "package wacc\n\nimport org.scalatest.flatspec.AnyFlatSpec\nimport org.scalatest.matchers.should.Matchers\nimport org.scalatest.Tag\nimport scala.util.matching.Regex\n\n/** Base trait for all WACC tests using the wacc-examples repository. Provides\n  * metadata parsing and test discovery logic.\n  */\ntrait WaccTestBase extends AnyFlatSpec with Matchers {\n    protected val TagName: String\n    protected lazy val TestTag = Tag(TagName)\n\n    protected val examplesPath = os.pwd / \"wacc-examples\"\n    protected val examplesExist = os.exists(examplesPath)\n    protected val activePatterns =\n        Set(\"valid/\", \"invalid/syntaxErr/\", \"invalid/semanticErr/\").map(\n            os.RelPath(_)\n        )\n\n    protected case class ProgramMetadata(\n        expectedOutput: Option[String],\n        expectedExitCode: Int,\n        expectedInput: Option[String]\n    )\n\n    protected def parseMetadata(program: os.Path): ProgramMetadata = {\n        val lines = os.read.lines(program).toList\n        def stripHash(l: String): String =\n            l.dropWhile(_.isWhitespace).drop(1).dropWhile(_.isWhitespace)\n\n        val outIdx = lines.indexWhere(_.trim == \"# Output:\")\n        val exIdx = lines.indexWhere(_.trim.startsWith(\"# Exit:\"))\n        val prIdx = lines.indexWhere(l =>\n            l.trim.startsWith(\"# Program:\") || l.trim.startsWith(\"#Program:\")\n        )\n        val inIdx = lines.indexWhere(l =>\n            l.trim.startsWith(\"# Input:\") || l.trim.startsWith(\"#Input:\")\n        )\n\n        val input = if (inIdx >= 0) {\n            val l = lines(inIdx).trim\n            val prefix = if (l.startsWith(\"# Input:\")) \"# Input:\" else \"#Input:\"\n            Some(l.stripPrefix(prefix).trim)\n        } else None\n\n        val exitCode = if (exIdx >= 0 && exIdx + 1 < lines.length) {\n            stripHash(lines(exIdx + 1))\n                .takeWhile(_.isDigit)\n                .toIntOption\n                .getOrElse(0)\n        } else 0\n\n        val outEnd =\n            if (exIdx >= 0) exIdx else if (prIdx >= 0) prIdx else lines.length\n        val output = if (outIdx >= 0 && outEnd > outIdx) {\n            val content = lines\n                .slice(outIdx + 1, outEnd)\n                .filter(_.trim.startsWith(\"#\"))\n                .map(stripHash)\n                .filter(_.nonEmpty)\n                .mkString(\"\\n\")\n            if (content.isEmpty) None else Some(content)\n        } else None\n\n        ProgramMetadata(output, exitCode, input)\n    }\n\n    protected val (addrWildcard, runtimeErrWildcard) =\n        (\"#addrs#\", \"#runtime_error#\")\n    // Robust regex that accepts hex addresses OR Interpreter-style array(1)/pair(1)\n    protected val addrRegex = \"(?:0x[0-9a-fA-F]+|(?:array|pair)\\\\(\\\\d+\\\\))\"\n    protected val runtimeErrRegex = \".+\"\n\n    protected def expectedToRegex(expected: String): Regex = {\n        val wildcardPattern = java.util.regex.Pattern.compile(\n            s\"${java.util.regex.Pattern.quote(addrWildcard)}|${java.util.regex.Pattern.quote(runtimeErrWildcard)}\"\n        )\n        val matcher = wildcardPattern.matcher(expected)\n        val regex = new StringBuilder(\"\\\\A\")\n        var last = 0\n        while (matcher.find()) {\n            regex.append(\n                java.util.regex.Pattern\n                    .quote(expected.substring(last, matcher.start()))\n            )\n            regex.append(\n                if (matcher.group() == addrWildcard) addrRegex\n                else runtimeErrRegex\n            )\n            last = matcher.end()\n        }\n        regex.append(java.util.regex.Pattern.quote(expected.substring(last)))\n        regex.append(\"\\\\z\")\n        regex.toString.r\n    }\n\n    protected def runStrategy(\n        program: os.Path,\n        meta: ProgramMetadata,\n        expectedCompileCode: Int,\n        checkOutput: Boolean\n    ): Unit\n\n    protected def runWaccTests(\n        directory: os.Path,\n        expectedCompileCode: Int,\n        category: String,\n        checkOutput: Boolean = false\n    ): Unit = {\n        if (!examplesExist) return\n        for (program <- os.walk(directory).filter(_.ext == \"wacc\")) {\n            val relativePath = program.relativeTo(examplesPath)\n            it should s\"correctly handle $category: $relativePath\" taggedAs (TestTag) in {\n                if (!activePatterns.exists(relativePath.startsWith)) pending\n                runStrategy(\n                    program,\n                    parseMetadata(program),\n                    expectedCompileCode,\n                    checkOutput\n                )\n            }\n        }\n    }\n}\n"
